from pathlib import Path
import subprocess

def rc(s):
    return s.translate(str.maketrans('acgt','tgca'))[::-1]

def tm(seq):
    return float(subprocess.check_output(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq],text=True).strip())

def parse(path):
    seqs={}; name=None; buf=[]
    for line in Path(path).read_text().splitlines():
        line=line.strip()
        if not line: continue
        if line.startswith('>'):
            if name: seqs[name]=''.join(buf).lower()
            name=line[1:]; buf=[]
        else: buf.append(line)
    if name: seqs[name]=''.join(buf).lower()
    return seqs
seqs=parse('/app/sequences.fasta')
inp=seqs['input']; out=seqs['output']
# exact insertion
p=0
while p<min(len(inp),len(out)) and inp[p]==out[p]: p+=1
s=0
while s < len(inp)-p and s < len(out)-p and inp[-1-s]==out[-1-s]: s+=1
insert=out[p:len(out)-s]
left=inp[:p]; right=inp[p:]
print('split',p,'insert',insert,'len',len(insert))
found=[]
for a in range(15,46):
    anneal_rev=left[-a:]
    tm_rev=tm(anneal_rev)
    if not 58<=tm_rev<=72: continue
    for b in range(15,46):
        anneal_fwd=right[:b]
        tm_fwd=tm(anneal_fwd)
        if not 58<=tm_fwd<=72 or abs(tm_fwd-tm_rev)>5: continue
        # split insert between rc(rev) suffix and fwd prefix
        for x in range(len(insert)+1):
            # rc(rev)=anneal_rev + insert[:x]
            # fwd=insert[x:] + anneal_fwd
            rev=rc(insert[:x]) + rc(anneal_rev)
            fwd=insert[x:] + anneal_fwd
            concat=rc(rev)+fwd
            pos=concat.find(insert)
            if pos==-1: continue
            der_rev=concat[:pos]
            der_fwd=concat[pos+len(insert):]
            if der_rev!=anneal_rev or der_fwd!=anneal_fwd:
                continue
            found.append((a,b,x,tm_rev,tm_fwd,fwd,rev))
found.sort(key=lambda t:(t[0]+t[1], abs(t[3]-t[4]), max(t[0],t[1]), t[2]))
print('found',len(found))
for row in found[:30]:
    a,b,x,tr,tf,fwd,rev=row
    print({'anneal_rev_len':a,'anneal_fwd_len':b,'x':x,'tm_rev':round(tr,2),'tm_fwd':round(tf,2),'fwd':fwd,'rev':rev})
